import React, { useMemo, useState } from "react";

export default function PricingPage(props) {
  const [billing, setBilling] = useState("monthly"); // "monthly" | "yearly"

  const tiers = useMemo(
    () => [
      {
        name: "Basic",
        price: billing === "monthly" ? 10 : 100,
        unit: billing === "monthly" ? "/mo" : "/yr",
        blurb: "Simple storage for personal projects and light sharing.",
        cta: "Start Basic",
        accent: "border-slate-200",
        perks: ["500 GB storage", "Email support", "Secure sharing links"],
      },
      {
        name: "Pro",
        price: billing === "monthly" ? 20 : 200,
        unit: billing === "monthly" ? "/mo" : "/yr",
        blurb: "Best for creators and small teams who collaborate daily.",
        cta: "Go Pro",
        accent: "border-indigo-500",
        tag: "Most Popular",
        perks: ["2 TB storage", "Priority support", "Version history (90 days)"],
      },
      {
        name: "Enterprise",
        price: billing === "monthly" ? 50 : 500,
        unit: billing === "monthly" ? "/mo" : "/yr",
        blurb: "Advanced security, controls, and scale for organizations.",
        cta: "Contact Sales",
        accent: "border-slate-200",
        perks: ["Unlimited storage", "SLA + dedicated support", "SSO/SAML + SCIM"],
      },
    ],
    [billing]
  );

  const features = useMemo(
    () => [
      { label: "Storage included", Basic: "500 GB", Pro: "2 TB", Enterprise: "Unlimited" },
      { label: "File version history", Basic: "30 days", Pro: "90 days", Enterprise: "365 days" },
      { label: "Upload limit per file", Basic: "5 GB", Pro: "50 GB", Enterprise: "200 GB" },
      { label: "Secure sharing links", Basic: "Yes", Pro: "Yes", Enterprise: "Yes" },
      { label: "Team workspaces", Basic: "—", Pro: "Up to 10", Enterprise: "Unlimited" },
      { label: "Admin console", Basic: "—", Pro: "Basic", Enterprise: "Advanced" },
      { label: "SSO (SAML) + SCIM", Basic: "—", Pro: "—", Enterprise: "Included" },
      { label: "Audit logs", Basic: "—", Pro: "Limited", Enterprise: "Full" },
      { label: "Data residency options", Basic: "—", Pro: "—", Enterprise: "Available" },
      { label: "Support", Basic: "Email", Pro: "Priority", Enterprise: "Dedicated + SLA" },
    ],
    []
  );

  const container = { maxWidth: 1100, margin: "0 auto", padding: "40px 16px 56px" };
  const cardBase = {
    background: "#fff",
    borderRadius: 16,
    border: "1px solid",
    padding: 20,
    boxShadow: "0 8px 24px rgba(15, 23, 42, 0.08)",
  };

  return (
    <div style={{ background: "linear-gradient(180deg, #0b1020 0%, #0b1020 18%, #f8fafc 18%, #f8fafc 100%)" }}>
      <header style={container}>
        <div style={{ color: "#e2e8f0", display: "flex", justifyContent: "space-between", gap: 16, flexWrap: "wrap" }}>
          <div>
            <div style={{ fontWeight: 700, letterSpacing: 0.2 }}>NebulaDrive</div>
            <h1 style={{ margin: "10px 0 6px", fontSize: 34, lineHeight: 1.15, color: "#fff" }}>
              Storage that scales with your universe
            </h1>
            <p style={{ margin: 0, maxWidth: 720, color: "#cbd5e1" }}>
              Simple pricing, strong security, and fast sharing—built for individuals, teams, and enterprises.
            </p>
          </div>

          <div style={{ alignSelf: "center", background: "rgba(255,255,255,0.06)", border: "1px solid rgba(148,163,184,0.25)", borderRadius: 14, padding: 12 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              <span style={{ color: billing === "monthly" ? "#fff" : "#94a3b8", fontWeight: 600 }}>Monthly</span>
              <label style={{ position: "relative", width: 44, height: 26, display: "inline-block" }}>
                <input
                  aria-label="Toggle billing period"
                  type="checkbox"
                  checked={billing === "yearly"}
                  onChange={(e) => setBilling(e.target.checked ? "yearly" : "monthly")}
                  style={{ opacity: 0, width: 0, height: 0 }}
                />
                <span
                  aria-hidden="true"
                  style={{
                    position: "absolute",
                    inset: 0,
                    borderRadius: 999,
                    background: billing === "yearly" ? "#6366f1" : "rgba(148,163,184,0.35)",
                    transition: "background 160ms ease",
                    border: "1px solid rgba(255,255,255,0.18)",
                  }}
                />
                <span
                  aria-hidden="true"
                  style={{
                    position: "absolute",
                    top: 3,
                    left: billing === "yearly" ? 22 : 3,
                    width: 20,
                    height: 20,
                    borderRadius: 999,
                    background: "#fff",
                    transition: "left 160ms ease",
                    boxShadow: "0 4px 10px rgba(0,0,0,0.25)",
                  }}
                />
              </label>
              <span style={{ color: billing === "yearly" ? "#fff" : "#94a3b8", fontWeight: 600 }}>
                Yearly <span style={{ color: "#c7d2fe", fontWeight: 700 }}>(save 2 months)</span>
              </span>
            </div>
          </div>
        </div>
      </header>

      <main style={{ ...container, paddingTop: 18 }}>
        <section aria-label="Pricing tiers" style={{ display: "grid", gridTemplateColumns: "repeat(3, minmax(0, 1fr))", gap: 16 }}>
          {tiers.map((t) => (
            <div key={t.name} style={{ ...cardBase, borderColor: t.name === "Pro" ? "#6366f1" : "#e2e8f0" }}>
              <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between", gap: 10 }}>
                <h2 style={{ margin: 0, fontSize: 18, color: "#0f172a" }}>{t.name}</h2>
                {t.tag ? (
                  <span style={{ fontSize: 12, fontWeight: 700, color: "#4338ca", background: "#eef2ff", border: "1px solid #c7d2fe", padding: "4px 8px", borderRadius: 999 }}>
                    {t.tag}
                  </span>
                ) : null}
              </div>
