import React from "react";

export default function BillingToggle(props) {
  const {
    value,
    onChange,
    monthlyLabel = "Monthly",
    yearlyLabel = "Yearly",
    yearlyHint = "Save with annual billing",
    id = "nebula-billing-toggle",
    disabled = false,
    className = "",
  } = props;

  const cadence = value === "yearly" ? "yearly" : "monthly";

  function setCadence(next) {
    if (disabled) return;
    if (next !== "monthly" && next !== "yearly") return;
    if (typeof onChange === "function") onChange(next);
  }

  function onKeyDown(e) {
    if (disabled) return;
    if (e.key === "ArrowLeft") setCadence("monthly");
    if (e.key === "ArrowRight") setCadence("yearly");
    if (e.key === " " || e.key === "Enter") {
      e.preventDefault();
      setCadence(cadence === "monthly" ? "yearly" : "monthly");
    }
  }

  const isYearly = cadence === "yearly";

  return (
    <div className={className} aria-label="Billing cadence">
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <span
          id={`${id}-monthly`}
          style={{
            fontSize: 14,
            fontWeight: 600,
            color: isYearly ? "#6B7280" : "#111827",
            userSelect: "none",
          }}
        >
          {monthlyLabel}
        </span>

        <button
          type="button"
          role="switch"
          aria-checked={isYearly}
          aria-labelledby={`${id}-monthly ${id}-yearly`}
          onClick={() => setCadence(isYearly ? "monthly" : "yearly")}
          onKeyDown={onKeyDown}
          disabled={disabled}
          style={{
            position: "relative",
            width: 56,
            height: 32,
            borderRadius: 999,
            border: `1px solid ${isYearly ? "#2563EB" : "#D1D5DB"}`,
            background: isYearly ? "rgba(37, 99, 235, 0.12)" : "#F9FAFB",
            padding: 0,
            cursor: disabled ? "not-allowed" : "pointer",
            outline: "none",
            boxShadow: "0 1px 0 rgba(0,0,0,0.02)",
          }}
        >
          <span
            aria-hidden="true"
            style={{
              position: "absolute",
              top: 3,
              left: isYearly ? 28 : 3,
              width: 26,
              height: 26,
              borderRadius: 999,
              background: "#FFFFFF",
              border: "1px solid rgba(17,24,39,0.12)",
              boxShadow: "0 6px 18px rgba(17,24,39,0.12)",
              transition: "left 180ms ease",
            }}
          />
        </button>

        <span
          id={`${id}-yearly`}
          style={{
            fontSize: 14,
