import React from "react";
import PropTypes from "prop-types";

const styles = {
  wrap: { display: "flex", flexDirection: "column", gap: 6 },
  row: { display: "flex", alignItems: "baseline", gap: 8, flexWrap: "wrap" },
  price: {
    fontSize: 36,
    fontWeight: 750,
    letterSpacing: "-0.02em",
    lineHeight: 1.05,
    color: "#0b1220",
  },
  cadence: {
    fontSize: 14,
    fontWeight: 600,
    color: "rgba(11, 18, 32, 0.7)",
  },
  subRow: { display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" },
  savings: {
    fontSize: 13,
    fontWeight: 650,
    color: "#0a7a4b",
    background: "rgba(10, 122, 75, 0.10)",
    border: "1px solid rgba(10, 122, 75, 0.25)",
    padding: "4px 8px",
    borderRadius: 999,
  },
  helper: { fontSize: 13, color: "rgba(11, 18, 32, 0.72)" },
  srOnly: {
    position: "absolute",
    width: 1,
    height: 1,
    padding: 0,
    margin: -1,
    overflow: "hidden",
    clip: "rect(0, 0, 0, 0)",
    whiteSpace: "nowrap",
    border: 0,
  },
};

function formatCurrency(value, currency = "USD", locale = "en-US") {
  if (!Number.isFinite(value)) return null;
  return new Intl.NumberFormat(locale, {
    style: "currency",
    currency,
    maximumFractionDigits: value % 1 === 0 ? 0 : 2,
  }).format(value);
}

function toCadenceLabel(cadence) {
  if (cadence === "yearly") return "/yr";
  return "/mo";
}

function computeSavingsText(monthly, yearly, currency, locale) {
  if (!Number.isFinite(monthly) || !Number.isFinite(yearly)) return null;
  if (monthly <= 0 || yearly <= 0) return null;

  const annualFromMonthly = monthly * 12;
  const rawSavings = annualFromMonthly - yearly;
  if (rawSavings <= 0) return null;

  const pct = Math.round((rawSavings / annualFromMonthly) * 100);
  const money = formatCurrency(rawSavings, currency, locale);
  if (!money) return null;

  return pct > 0 ? `Save ${pct}% (${money})` : `Save ${money}`;
}

export default function PriceDisplay(props) {
  const {
    cadence,
    monthlyPrice,
    yearlyPrice,
    currency,
    locale,
    showSavings,
    savingsText,
    helperText,
    className,
    style,
  } = props;

  const activePrice = cadence === "yearly" ? yearlyPrice : monthlyPrice;
  const formatted = formatCurrency(activePrice, currency, locale);
  const cadenceLabel = toCadenceLabel(cadence);

  const computedSavings =
    showSavings && cadence === "yearly"
      ? computeSavingsText(monthlyPrice, yearlyPrice, currency, locale)
      : null;

  const finalSavingsText =
    cadence === "yearly" ? (savingsText ?? computedSavings) : null;

  return (
    <div className={className} style={{ ...styles.wrap, ...style }}>
      <div style={styles.row}>
        <span style={styles.price} aria-label="Plan price">
          {formatted ?? "Contact sales"}
        </span>
        <span style={styles.cadence} aria-label="Billing cadence">
          {formatted ? cadenceLabel : ""}
        </span>
      </div>

      {(finalSavingsText || helperText) && (
        <div style={styles.subRow}>
          {finalSavingsText && (
            <span style={styles.savings}>
              <span style={styles.srOnly}>Yearly billing savings: </span>
              {finalSavingsText}
            </span>
          )}
          {helperText && <span style={styles.helper}>{helperText}</span>}
        </div>
      )}
    </div>
  );
}

PriceDisplay.propTypes = {
  cadence: PropTypes.oneOf(["monthly", "yearly"]).isRequired,
  monthlyPrice: PropTypes.number,
