import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';

import PricingPage from './components/PricingPage.jsx';
import PageShell from './components/PageShell.jsx';
import PricingHeader from './components/PricingHeader.jsx';
import BillingToggle from './components/BillingToggle.jsx';
import PricingTierGrid from './components/PricingTierGrid.jsx';
import PricingCard from './components/PricingCard.jsx';
import MostPopularBadge from './components/MostPopularBadge.jsx';
import PriceDisplay from './components/PriceDisplay.jsx';
import PrimaryButton from './components/PrimaryButton.jsx';
import SecondaryButton from './components/SecondaryButton.jsx';
import FeatureComparisonSection from './components/FeatureComparisonSection.jsx';
import FeatureComparisonTable from './components/FeatureComparisonTable.jsx';

function PricingRoute() {
  const [billingCadence, setBillingCadence] = useState('monthly'); // 'monthly' | 'yearly'

  const plans = useMemo(
    () => [
      {
        id: 'basic',
        name: 'Basic',
        description: 'Essential cloud storage for everyday files.',
        price: { monthly: 10, yearly: 100 },
        cta: { label: 'Start Free Trial', variant: 'secondary' },
        highlights: ['1 TB storage', 'Secure sharing links', 'Email support'],
        popular: false,
      },
      {
        id: 'pro',
        name: 'Pro',
        description: 'For power users who need speed, sharing, and control.',
        price: { monthly: 20, yearly: 200 },
        cta: { label: 'Choose Pro', variant: 'primary' },
        highlights: ['5 TB storage', 'Version history', 'Priority support'],
        popular: true,
      },
      {
        id: 'enterprise',
        name: 'Enterprise',
        description: 'Advanced security, admin controls, and custom terms.',
        price: { monthly: 50, yearly: 500 },
        cta: { label: 'Contact Sales', variant: 'primary' },
        highlights: ['Unlimited storage', 'SSO & SCIM', 'Dedicated success manager'],
        popular: false,
      },
    ],
    []
  );

  const comparisonRows = useMemo(
    () => [
      { feature: 'Storage', basic: '1 TB', pro: '5 TB', enterprise: 'Unlimited' },
      { feature: 'File versioning', basic: '30 days', pro: '180 days', enterprise: 'Unlimited' },
      { feature: 'Sharing controls', basic: 'Standard', pro: 'Advanced', enterprise: 'Advanced + DLP' },
      { feature: 'Admin console', basic: '—', pro: 'Team settings', enterprise: 'Full policy & audit' },
      { feature: 'Security', basic: '2FA', pro: '2FA + device approvals', enterprise: 'SSO, SCIM, SIEM export' },
      { feature: 'Support', basic: 'Email', pro: 'Priority email', enterprise: '24/7 + dedicated manager' },
    ],
    []
  );

  const faqs = useMemo(
    () => [
      {
        q: 'Can I switch between monthly and yearly billing?',
        a: 'Yes. You can change your billing cadence at any time from your account settings. Any remaining balance is prorated automatically.',
      },
      {
        q: 'Is my data encrypted?',
        a: 'NebulaDrive encrypts files in transit and at rest. Enterprise customers can enable additional security controls and audit reporting.',
      },
      {
        q: 'Do you offer team accounts?',
        a: 'Pro supports small teams, while Enterprise provides centralized administration, SSO/SCIM, and advanced policy management.',
      },
      {
        q: 'What happens if I exceed my storage limit?',
        a: 'We’ll notify you before you hit your limit. You can upgrade instantly to expand capacity without disrupting access to your files.',
      },
    ],
    []
  );

  return (
    <PageShell>
      <PricingPage>
        <PricingHeader
          productName="NebulaDrive"
          title="Simple, transparent pricing"
          subtitle="Secure cloud storage that scales from personal projects to enterprise deployments."
        />

        <BillingToggle value={billingCadence} onChange={setBillingCadence} />

        <PricingTierGrid>
          {plans.map((plan) => (
            <PricingCard
              key={plan.id}
              name={plan.name}
              description={plan.description}
              highlighted={plan.popular}
              badge={plan.popular ? <MostPopularBadge label="Most Popular" /> : null}
              price={
                <PriceDisplay
                  amount={plan.price[billingCadence]}
                  cadence={billingCadence === 'monthly' ? 'mo' : 'yr'}
                />
              }
              cta={
                plan.cta.variant === 'primary' ? (
                  <PrimaryButton>{plan.cta.label}</PrimaryButton>
                ) : (
                  <SecondaryButton>{plan.cta.label}</SecondaryButton>
                )
              }
              highlights={plan.highlights}
            />
          ))}
        </PricingTierGrid>

        <FeatureComparisonSection
          title="Compare plans"
          subtitle="Choose the right level of storage, security, and support for your team."
        >
          <FeatureComparisonTable columns={plans.map((p) => p.name)} rows={comparisonRows} />
        </FeatureComparisonSection>

        <section aria-labelledby="faq-title">
          <h2 id="faq-title">Frequently asked questions</h2>
          {faqs.map((item, idx) => (
            <details key={idx}>
              <summary>{item.q}</summary>
              <div>{item.a}</div>
            </details>
          ))}
        </section>
      </PricingPage>
    </PageShell>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/pricing" element={<PricingRoute />} />
        <Route path="/" element={<Navigate to="/pricing" replace />} />
        <Route path="*" element={<Navigate to="/pricing" replace />} />
      </Routes>
    </BrowserRouter>
  );
}
